INSERT INTO content_translations (resource_type, resource_key, lang, text, updated_at) VALUES
('school_learning_question', 'question1', 'kn', 'ನಿಮಗೆ ಶಾಲೆಗೆ ಬರಲು ಇಷ್ಟವೇ? ಯಾಕೆ?', NOW()),
('school_learning_question', 'question2', 'kn', 'ಶಾಲೆಯಲ್ಲಿ ನೀವು ಏನು ಕಲಿಯಲು ಇಷ್ಟಪಡುತ್ತೀರಿ?', NOW()),
('school_learning_question', 'question3', 'kn', 'ನೀವು ಶಾಲೆಯಲ್ಲಿ ಕಲಿಯಲು ಇಷ್ಟಪಡದಿರುವ ಕಾರಣಗಳೇನು? ವಿವರಿಸಿ.', NOW()),
('school_learning_question', 'question4', 'kn', 'ಶಾಲೆಯಲ್ಲಿ ನಿಮಗೆ ಆತ್ಮೀಯ ಸ್ನೇಹಿತರು ಯಾರು? ಅವರಲ್ಲಿ ಇರುವ ಯಾವ ಗುಣಗಳು / ಸಂಗತಿಗಳು ಅವರನ್ನು ನಿಮ್ಮ ಆತ್ಮೀಯ ಸ್ನೇಹಿತರಾಗಿಸಿದ್ದಾರೆ?', NOW()),
('school_learning_question', 'question5', 'kn', 'ನೀವು ಹೆಚ್ಚು ಇಷ್ಟಪಡುವ ಪಠ್ಯ ವಿಷಯಗಳು ಯಾವುವು? ಬರೆಯಿರಿ.', NOW()),
('school_learning_question', 'question6', 'kn', 'ನೀವು ಈ ವಿಷಯವನ್ನು ಏಕೆ ಇಷ್ಟಪಡುತ್ತೀರಿ? ಕಾರಣವನ್ನು ಬರೆಯಿರಿ.', NOW()),
('school_learning_question', 'question7', 'kn', 'ನಿಮಗೆ ಕಲಿಯಲು ಇಷ್ಟವಿಲ್ಲದ ಪಠ್ಯ ವಿಷಯಗಳು ಯಾವವು?', NOW()),
('school_learning_question', 'question8', 'kn', 'ಮೇಲಿನ ವಿಷಯಗಳಲ್ಲಿ ನಿಮಗೆ ಕಡಿಮೆ ಆಸಕ್ತಿ ಏಕೆ? ಈ ವಿಷಯಗಳನ್ನು ಕಲಿಯಲು ನೀವು ಯಾವ ಸಹಾಯಗಳನ್ನು ಪಡೆದಿದ್ದೀರಾ?', NOW()),
('school_learning_question', 'question9', 'kn', 'ನೀವು ಹೆಚ್ಚು ಅಂಕ ಗಳಿಸುವ ವಿಷಯಗಳು ಯಾವುವು?', NOW()),
('school_learning_question', 'question10', 'kn', 'ನೀವು ಕಡಿಮೆ ಅಂಕ ಗಳಿಸುವ ವಿಷಯಗಳು ಯಾವುವು?', NOW()),
('school_learning_question', 'question11', 'kn', 'ಈ ಕೆಳಗಿನ ಯಾವ ಕಲಿಕಾ ವಿಧಾನಗಳನ್ನು ನೀವು ಹೆಚ್ಚು ಇಷ್ಟಪಡುತ್ತೀರಿ? (ನಿಮಗೆ ಅನ್ವಯವಾಗುವುದನ್ನು ✔ ಎಂದು ಗುರುತು ಮಾಡಿ)', NOW()),
('school_learning_question', 'question12', 'kn', 'ನೀವು ಒಬ್ಬರೇ ಕಲಿಯಲು ಇಷ್ಟಪಡುತ್ತೀರಾ ಅಥವಾ ಗುಂಪಿನಲ್ಲಿ ಕಲಿಯಲು ಇಷ್ಟಪಡುತ್ತೀರಾ? ಏಕೆ? ಕಾರಣ ಬರೆಯಿರಿ.', NOW()),
('school_learning_question', 'question13', 'kn', 'ಶಾಲೆಯಲ್ಲಿ ನೀವು ನಿಮ್ಮ ಸ್ನೇಹಿತರಿಂದ ಕಲಿಯುತ್ತೀರಾ? ಶಾಲೆಯಲ್ಲಿ ಇತ್ತೀಚೆಗೆ ಸ್ನೇಹಿತರಿಂದ ಕಲಿತ ಕೆಲವು ವಿಷಯಗಳನ್ನು ಪಟ್ಟಿ ಮಾಡಿ.', NOW()),
('school_learning_question', 'question14', 'kn', 'ಪಠ್ಯ ವಿಷಯಗಳನ್ನು ಹೊರತುಪಡಿಸಿ, ಶಾಲೆಗೆ ನಿಮ್ಮನ್ನು ಆಕರ್ಷಿಸುವ ಅಂಶಗಳು ಯಾವುವು?', NOW()),
('school_learning_question', 'question15', 'kn', 'ನಿಮ್ಮ ನೆಚ್ಚಿನ 2 ಶಿಕ್ಷಕರು ಯಾರು ಮತ್ತು ಏಕೆ? ಈ 2 ಶಿಕ್ಷಕರು ನಿಮ್ಮ ಮೇಲೆ ಹೇಗೆ ಪ್ರಭಾವ ಬೀರಿದ್ದಾರೆ?', NOW()),
('school_learning_question', 'question16', 'kn', 'ಶಾಲೆಯಲ್ಲಿ ನಿಮಗೆ ತುಂಬಾ ಯಶಸ್ಸು ಅಥವಾ ತೃಪ್ತಿ ಅನುಭವಿಸುವಂತೆ ಮಾಡಿದ ಒಂದು ನಿರ್ದಿಷ್ಟ ಘಟನೆ / ಅನುಭವ ಇದೆಯೇ? ಅದು ಏನು?', NOW()),
('school_learning_question', 'question17', 'kn', 'ನಿಮ್ಮ ಕನಸು ಮತ್ತು ನಿರೀಕ್ಷೆಗಳನ್ನು ಸಾಧಿಸಲು ಶಾಲೆಯಲ್ಲಿ ನೀವು ಕಲಿತ ವಿಷಯಗಳು ನಿಮಗೆ ಹೇಗೆ ಸಹಾಯ ಮಾಡುತ್ತವೆ?', NOW()),
('school_learning_question', 'question18', 'kn', 'ನಿಮ್ಮ ಶಾಲೆಯಲ್ಲಿ ಯಾವ ಯಾವ ಸಂಗತಿಗಳು ಬದಲಾವಣೆಯಾಗಬೇಕು ಎಂದು ನೀವು ಬಯಸುತ್ತೀರಿ? ಅದಕ್ಕೆ ಕಾರಣವೇನು?', NOW()),
('school_learning_question', 'question19', 'kn', 'ನೀವು ಅಭಿವ್ಯಕ್ತಿ ಮಾಡಲು ಯಾವುದಾದರೂ ವಿಶೇಷ ಸ್ಥಳ ಇದೆಯೇ? ಅದು ಯಾಕೆ ಅಗತ್ಯ?', NOW()),
('school_learning_question', 'question20', 'kn', 'ನಿಮ್ಮ ಜೀವನದಲ್ಲಿ ಕಲಿಕೆಗೆ ಸಂಬಂಧಿಸಿದಂತೆ ಶಾಲೆಯ ಮಹತ್ವದ ಪಾತ್ರವಿದೆಯೇ? ನಿಮ್ಮ ಅಭಿಪ್ರಾಯವನ್ನು ಬರೆಯಿರಿ.', NOW()),
('school_learning_question', 'question21', 'kn', 'ಶಾಲೆಯ ಚಟುವಟಿಕೆಗಳು ಮತ್ತು ಕಲಿಕೆಯ ಬಗ್ಗೆ ನಿಮ್ಮ ಪಾಲಕರೊಂದಿಗೆ ಚರ್ಚಿಸಲು ನಿಮಗೆ ಇಷ್ಟವೇ? ನೀವು ಅವರೊಂದಿಗೆ ಯಾವ ವಿಷಯಗಳನ್ನು ಚರ್ಚಿಸುತ್ತೀರಿ?', NOW())
INSERT INTO content_translations (resource_type, resource_key, lang, text, updated_at) VALUES
('school_learning_question', 'question1', 'ta', 'உங்களுக்கு பள்ளிக்கு செல்ல விருப்பமா? ஏன்?', NOW()),
('school_learning_question', 'question2', 'ta', 'பள்ளியில் நீங்கள் என்ன கற்றுக்கொள்ள விரும்புகிறீர்கள்?', NOW()),
('school_learning_question', 'question3', 'ta', 'பள்ளியில் கற்றுக்கொள்ள உங்களுக்கு பிடிக்காத காரணங்கள் என்ன? விளக்குங்கள்.', NOW()),
('school_learning_question', 'question4', 'ta', 'பள்ளியில் உங்களுக்கு நெருங்கிய நண்பர்கள் யார்? அவர்களிடம் உள்ள எந்த குணங்கள் / அம்சங்கள் அவர்களை உங்கள் நெருங்கிய நண்பர்களாக ஆக்கியது?', NOW()),
('school_learning_question', 'question5', 'ta', 'நீங்கள் அதிகம் விரும்பும் பாடப்பிரிவுகள் எவை? எழுதுங்கள்.', NOW()),
('school_learning_question', 'question6', 'ta', 'நீங்கள் இந்த பாடத்தை ஏன் விரும்புகிறீர்கள்? காரணத்தை எழுதுக.', NOW()),
('school_learning_question', 'question7', 'ta', 'உங்களுக்கு கற்க விருப்பமில்லாத பாடப்பிரிவுகள் எவை?', NOW()),
('school_learning_question', 'question8', 'ta', 'மேலே கூறிய பாடங்களில் உங்களுக்கு ஏன் குறைந்த ஆர்வம் உள்ளது? இந்த பாடங்களை கற்க நீங்கள் எந்த உதவிகளை பெற்றீர்கள்?', NOW()),
('school_learning_question', 'question9', 'ta', 'நீங்கள் அதிக மதிப்பெண் பெறும் பாடங்கள் எவை?', NOW()),
('school_learning_question', 'question10', 'ta', 'நீங்கள் குறைந்த மதிப்பெண் பெறும் பாடங்கள் எவை?', NOW()),
('school_learning_question', 'question11', 'ta', 'கீழ்க்கண்ட எந்த கற்றல் முறைகளை நீங்கள் அதிகமாக விரும்புகிறீர்கள்? (உங்களுக்கு பொருந்துவதை ✔ என்று குறிக்கவும்)', NOW()),
('school_learning_question', 'question12', 'ta', 'நீங்கள் தனியாகக் கற்றுக்கொள்ள விரும்புகிறீர்களா அல்லது குழுவாக கற்றுக்கொள்ள விரும்புகிறீர்களா? ஏன்? காரணத்தை எழுதுங்கள்.', NOW()),
('school_learning_question', 'question13', 'ta', 'பள்ளியில் நீங்கள் உங்கள் நண்பர்களிடமிருந்து கற்றுக்கொள்கிறீர்களா? பள்ளியில் சமீபத்தில் நண்பர்களிடமிருந்து கற்ற சில விஷயங்களை பட்டியலிடுங்கள்.', NOW()),
('school_learning_question', 'question14', 'ta', 'பாடப்புத்தகப் பாடங்களைத் தவிர, பள்ளிக்குச் செல்ல உங்களை ஈர்க்கும் அம்சங்கள் எவை?', NOW()),
('school_learning_question', 'question15', 'ta', 'உங்களுக்கு பிடித்த 2 ஆசிரியர்கள் யார்? ஏன்? இந்த 2 ஆசிரியர்கள் உங்கள் மீது எவ்வாறு தாக்கம் ஏற்படுத்தியுள்ளனர்?', NOW()),
('school_learning_question', 'question16', 'ta', 'பள்ளியில் உங்களுக்கு மிகுந்த வெற்றி அல்லது திருப்தி உணர்வை ஏற்படுத்திய ஒரு குறிப்பிட்ட நிகழ்வு / அனுபவம் உள்ளதா? அது என்ன?', NOW()),
('school_learning_question', 'question17', 'ta', 'உங்கள் கனவுகள் மற்றும் எதிர்பார்ப்புகளை அடைய, பள்ளியில் நீங்கள் கற்ற விஷயங்கள் உங்களுக்கு எவ்வாறு உதவுகின்றன?', NOW()),
('school_learning_question', 'question18', 'ta', 'உங்கள் பள்ளியில் எந்த எந்த விஷயங்கள் மாற்றப்பட வேண்டும் என்று நீங்கள் விரும்புகிறீர்கள்? அதற்கான காரணம் என்ன?', NOW()),
('school_learning_question', 'question19', 'ta', 'நீங்கள் உங்களை வெளிப்படுத்துவதற்கான ஏதேனும் சிறப்பு இடம் உள்ளதா? அது ஏன் அவசியம்?', NOW()),
('school_learning_question', 'question20', 'ta', 'உங்கள் வாழ்க்கை, கற்றலுடன் தொடர்புடையதாக மாற்றுவதில் பள்ளிக்கு முக்கியமான பங்கு உள்ளதா? உங்கள் கருத்தை எழுதுங்கள்.', NOW()),
('school_learning_question', 'question21', 'ta', 'பள்ளியின் செயல்பாடுகள் மற்றும் கற்றல் குறித்து உங்கள் பெற்றோருடன் விவாதிக்க உங்களுக்கு விருப்பமா? அவர்களுடன் நீங்கள் எந்த விஷயங்களைப் பேசுகிறீர்கள்?', NOW())
INSERT INTO content_translations (resource_type, resource_key, lang, text, updated_at) VALUES
('school_learning_help', 'question1', 'ta', 'பள்ளிக்குச் செல்ல விருப்பம் உள்ளதா என்பதை காரணத்துடன் எழுதுங்கள்.', NOW()),
('school_learning_help', 'question2', 'ta', 'பள்ளியில் உங்களுக்கு பிடித்த கற்றல் விஷயங்களை எழுதுங்கள்.', NOW()),
('school_learning_help', 'question3', 'ta', 'கற்றலில் விருப்பமில்லாத காரணங்களை தெளிவாக எழுதுங்கள்.', NOW()),
('school_learning_help', 'question4', 'ta', 'உங்கள் நெருங்கிய நண்பர்கள் மற்றும் அவர்களின் நல்ல குணங்களை எழுதுங்கள்.', NOW()),
('school_learning_help', 'question5', 'ta', 'உங்களுக்கு பிடித்த பாடங்களை பட்டியலிடுங்கள்.', NOW()),
('school_learning_help', 'question6', 'ta', 'பாடம் எளிதாக இருப்பது, சுவாரசியமாக இருப்பது அல்லது ஆசிரியர் நன்றாக கற்பிப்பது காரணமாக இருக்கலாம்.', NOW()),
('school_learning_help', 'question7', 'ta', 'பாடம் கடினமாக இருப்பது அல்லது புரியாமல் இருப்பது காரணமாக சில பாடங்கள் பிடிக்காமல் இருக்கலாம்.', NOW()),
('school_learning_help', 'question8', 'ta', 'பாடம் கடினமாக இருப்பதால் ஆர்வம் குறையலாம், ஆசிரியர் மற்றும் நண்பர்களின் உதவி கற்றலுக்கு உதவுகிறது.', NOW()),
('school_learning_help', 'question9', 'ta', 'எளிதாக புரியும் மற்றும் விருப்பமான பாடங்களில் மாணவர்கள் அதிக மதிப்பெண் பெறுவார்கள்.', NOW()),
('school_learning_help', 'question10', 'ta', 'பாடம் புரியாமல் இருப்பது அல்லது பயிற்சி குறைவாக இருப்பது குறைந்த மதிப்பெண்களுக்கு காரணமாகும்.', NOW()),
('school_learning_help', 'question11', 'ta', 'மாணவர்கள் தங்களுக்கு எளிதாக புரியும் மற்றும் விருப்பமான கற்றல் முறையை தேர்வு செய்ய வேண்டும்', NOW()),
('school_learning_help', 'question12', 'ta', 'உங்களுக்கு பிடித்த கற்றல் முறையை தேர்வு செய்து காரணத்தை எழுதுங்கள்.', NOW()),
('school_learning_help', 'question13', 'ta', 'நண்பர்களிடமிருந்து கற்ற விஷயங்களை நினைத்து பட்டியலிடுங்கள்.', NOW()),
('school_learning_help', 'question14', 'ta', 'பள்ளி மீது விருப்பத்தை ஏற்படுத்தும் பிற செயல்கள் அல்லது அம்சங்களை எழுதுங்கள்.', NOW()),
('school_learning_help', 'question15', 'ta', 'பிடித்த ஆசிரியர்களையும் அவர்கள் உங்களை மாற்றிய விதத்தையும் எழுதுங்கள்.', NOW()),
('school_learning_help', 'question16', 'ta', 'உங்களுக்கு பெருமை அல்லது திருப்தி அளித்த பள்ளி நிகழ்வை எழுதுங்கள்.', NOW()),
('school_learning_help', 'question17', 'ta', 'பள்ளியில் கற்றதை உங்கள் கனவுகளுடன் தொடர்புபடுத்தி எழுதுங்கள்', NOW()),
('school_learning_help', 'question18', 'ta', 'மாற்றம் வேண்டிய விஷயங்களையும் அதற்கான காரணத்தையும் எழுதுங்கள்.', NOW()),
('school_learning_help', 'question19', 'ta', 'உங்களை வெளிப்படுத்தும் இடம் மற்றும் அதன் அவசியத்தை எழுதுங்கள்.', NOW()),
('school_learning_help', 'question20', 'ta', 'கற்றலில் பள்ளியின் பங்கைப் பற்றி உங்கள் கருத்தை எழுதுங்கள்.', NOW()),
('school_learning_help', 'question21', 'ta', 'பெற்றோருடன் நீங்கள் பேசும் பள்ளி தொடர்பான விஷயங்களை எழுதுங்கள்.', NOW())
